import heapq
def getSkyline(buildings):
    events = [(L, -H, R) for L, R, H in buildings]
    events += [(R, 0, 0) for _, R, _ in buildings]
    events.sort()
    res = [[0, 0]]; hp = [(0, float('inf'))]
    for x, h, r in events:
        if h < 0: heapq.heappush(hp, (h, r))
        while hp[0][1] <= x: heapq.heappop(hp)
        if res[-1][1] != -hp[0][0]: res.append([x, -hp[0][0]])
    return res[1:]

